import{_ as o,o as a,c as t,ak as r}from"./chunks/framework.Dx0ZwfXr.js";const u=JSON.parse('{"title":"InputConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-input-inputconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-input-inputconfiguration.md"}'),n={name:"api/reference/royalapps-community-rdp-winforms-configuration-input-inputconfiguration.md"};function i(s,e,l,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="inputconfiguration" tabindex="-1"><code>InputConfiguration</code> <a class="header-anchor" href="#inputconfiguration" aria-label="Permalink to “InputConfiguration”">​</a></h1><p>Input related configuration and settings.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.Input.InputConfiguration</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="acceleratorpassthrough-bool-↗" tabindex="-1"><code>AcceleratorPassthrough</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-acceleratorpassthrough" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#acceleratorpassthrough-bool-↗" aria-label="Permalink to “AcceleratorPassthrough (bool) ↗”">​</a></h3><p>Specifies whether keyboard accelerators should be passed to the server.</p><h3 id="allowbackgroundinput-bool-↗" tabindex="-1"><code>AllowBackgroundInput</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-allowbackgroundinput" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#allowbackgroundinput-bool-↗" aria-label="Permalink to “AllowBackgroundInput (bool) ↗”">​</a></h3><p>Specifies whether background input mode is enabled. When background input is enabled the client can accept input when the client does not have focus.</p><h3 id="disableclickdetection-bool" tabindex="-1"><code>DisableClickDetection</code> (<code>bool</code>) <a class="header-anchor" href="#disableclickdetection-bool" aria-label="Permalink to “DisableClickDetection (bool)”">​</a></h3><p>When <code>true</code>, a mouse click in the remote session does not transfer input focus to the session.</p><h3 id="enablewindowskey-bool-↗" tabindex="-1"><code>EnableWindowsKey</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-enablewindowskey" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#enablewindowskey-bool-↗" aria-label="Permalink to “EnableWindowsKey (bool) ↗”">​</a></h3><p>Specifies whether the Windows key can be used in the remote session.</p><h3 id="grabfocusonconnect-bool-↗" tabindex="-1"><code>GrabFocusOnConnect</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-grabfocusonconnect" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#grabfocusonconnect-bool-↗" aria-label="Permalink to “GrabFocusOnConnect (bool) ↗”">​</a></h3><p>Specifies whether the client control should have focus while connecting. The control does not attempt to grab focus from a window running in a different process.</p><h3 id="keyboardhookmode-bool-↗" tabindex="-1"><code>KeyboardHookMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientsecuredsettings-keyboardhookmode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#keyboardhookmode-bool-↗" aria-label="Permalink to “KeyboardHookMode (bool) ↗”">​</a></h3><p>Specifies the keyboard redirection settings, which specify how and when to apply Windows keyboard shortcut (for example, ALT+TAB).</p><h3 id="keyboardhooktoggleshortcutenabled-bool" tabindex="-1"><code>KeyboardHookToggleShortcutEnabled</code> (<code>bool</code>) <a class="header-anchor" href="#keyboardhooktoggleshortcutenabled-bool" aria-label="Permalink to “KeyboardHookToggleShortcutEnabled (bool)”">​</a></h3><p>When enabled, ctrl+alt+space can be used to toggle between local and remote keyboard hook modes. Only works when the session is in full screen mode.</p><h3 id="keyboardlayoutstr-string-↗" tabindex="-1"><code>KeyBoardLayoutStr</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-keyboardlayoutstr" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#keyboardlayoutstr-string-↗" aria-label="Permalink to “KeyBoardLayoutStr (string?) ↗”">​</a></h3><p>Specifies the name of the active input locale identifier (formerly called the keyboard layout) to use for the connection.</p><h3 id="relativemousemode-bool-↗" tabindex="-1"><code>RelativeMouseMode</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings6-relativemousemode" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#relativemousemode-bool-↗" aria-label="Permalink to “RelativeMouseMode (bool) ↗”">​</a></h3><p>Specifies whether the mouse should use relative mode. Contains VARIANT_TRUE if the mouse is in relative mode or VARIANT_FALSE if the mouse is in absolute mode. The mouse mode indicates how the ActiveX control calculates the mouse coordinates that it sends to the Remote Desktop Session Host (RD Session Host) server. When the mouse is in relative mode, the ActiveX control calculates mouse coordinates relative to the mouse&#39;s last position. When the mouse is in absolute mode, the ActiveX control calculates mouse coordinates relative to the desktop of the RD Session Host server.</p><p><a href="./../">Back to API index</a></p>',24)])])}const b=o(n,[["render",i]]);export{u as __pageData,b as default};
